final void newAttribute() {
if (attributes == null)
attributes = new Attributes();

if (pendingAttributeName == null) return;

if (pendingAttributeName.trim().isEmpty()) return;
pendingAttributeName = pendingAttributeName.trim();

if (pendingAttributeName.length() > 0 && pendingAttributeName.length() < 256) {
    Attribute attribute;
    if (hasPendingAttributeValue) {
        attribute = new Attribute(pendingAttributeName,
                pendingAttributeValue.length() > 0 ? pendingAttributeValue.toString() : pendingAttributeValueS);
    } else if (hasEmptyAttributeValue) {
        attribute = new Attribute(pendingAttributeName, "");
    } else {
        attribute = new BooleanAttribute(pendingAttributeName);
    }
    attributes.put(attribute);

    pendingAttributeName = null;
    hasEmptyAttributeValue = false;
    hasPendingAttributeValue = false;
    reset(pendingAttributeValue);
    pendingAttributeValueS = null;
} else {
    // Truncate attribute name to 255 characters for security reasons
    pendingAttributeName = pendingAttributeName.substring(0, 255);
    hasEmptyAttributeValue = true;
}
}
